GO
create PROCEDURE [dbo].[AST_FEWS_FLAG_PIDECAE]  
 -- Add the parameters for the stored procedure here    
 @@PIDECAE INT     
AS    

BEGIN    

SELECT CASE  @@PIDECAE
		WHEN 1 THEN 1
		ELSE 0
END
end
GO
/****** Object:  UserDefinedFunction [dbo].[AST_FEWS_GET_RESULTADO_CAE]    Script Date: 05/25/2016 10:40:26 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO
--SELECT DBO.AST_FEWS_GET_ID_CONSOLA(1233)
CREATE function [dbo].[AST_FEWS_GET_RESULTADO_CAE](@@AS_ID INT) 
RETURNS INT
AS
BEGIN 
	
--
-- OBTIENE EL ID DE LA CONSOLA
---
DECLARE @RESULTADO VARCHAR(4)
DECLARE @CUIT_AGS VARCHAR(11)
SET @CUIT_AGS ='30711897581'

SET @RESULTADO=ISNULL((SELECT ISNULL(RESULTADO,'') FROM  AST_FEWS_LOG 
					WHERE	
					AST_FEWS_LOG.CUIT_EMPRESA =@CUIT_AGS AND
					
					AST_FEWS_LOG.FECHA_COMPROBANTE =(SELECT CONVERT(VARCHAR(8),Asiento.as_FECHA,112) FROM Asiento WHERE AS_ID=@@AS_ID) AND
					
					AST_FEWS_LOG.TIPO_COMPROBANTE =(select comprt_alias from comprobantetipo where comprobantetipo.COMPRT_ID=
				(select comprt_id from Talonario where talonario.TAL_ID=
				(SELECT tal_id FROM Documentotipotalonario where DOC_ID=(SELECT asiento.DOC_ID FROM Asiento WHERE AS_ID=@@AS_ID) and cf_id=
				(select cf_id from Tercero where tercero.te_id=(SELECT asiento.TE_ID FROM Asiento WHERE AS_ID=@@AS_ID))))) AND 
					
					AST_FEWS_LOG.PUNTO_VENTA =(select RIGHT(Talonario.TAL_PREFIJO, 4) from Talonario where talonario.TAL_ID=
				(SELECT tal_id FROM Documentotipotalonario where DOC_ID=(SELECT asiento.DOC_ID FROM Asiento WHERE AS_ID=@@AS_ID) and cf_id=
				(select cf_id from Tercero where tercero.te_id=(SELECT asiento.TE_ID FROM Asiento WHERE AS_ID=@@AS_ID)))) AND 
					
					AST_FEWS_LOG.NUMERO_COMPROBANTE = (SELECT RIGHT(ASIENTO.AS_NUMERODOC,8) FROM Asiento WHERE AS_ID=@@AS_ID) AND
					
					AST_FEWS_LOG.TIPODOC_CLIENTE =(select te_TIPODOC from Tercero where tercero.te_id=(SELECT asiento.TE_ID FROM Asiento WHERE AS_ID=@@AS_ID)) AND
					
					AST_FEWS_LOG.NRODOC_CLIENTE = (select te_cuit from Tercero where tercero.te_id=(SELECT asiento.TE_ID FROM Asiento WHERE AS_ID=@@AS_ID)) AND
					
					AST_FEWS_LOG.IMPORTE_TOTAL	=case (SELECT mon_id FROM Asiento WHERE AS_ID=@@AS_ID)
								when -1 then ISNULL((SELECT ASIENTO.AS_TOTAL FROM Asiento WHERE AS_ID=@@AS_ID),0)
								else ISNULL((SELECT ASIENTO.AS_TOTAL FROM Asiento WHERE AS_ID=@@AS_ID),0)/ISNULL((SELECT asiento.AS_MonedaCambio FROM Asiento WHERE AS_ID=@@AS_ID),1)
								end),'')
  RETURN @RESULTADO
END
GO
/****** Object:  UserDefinedFunction [dbo].[AST_FEWS_GET_ID_CONSOLA]    Script Date: 05/25/2016 10:40:26 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO
--SELECT DBO.AST_FEWS_GET_ID_CONSOLA(1233)
CREATE function [dbo].[AST_FEWS_GET_ID_CONSOLA](@@AS_ID INT) 
RETURNS INT
AS
BEGIN 
	
--
-- OBTIENE EL ID DE LA CONSOLA
---
DECLARE @ID_CONSOLA INT

SET @ID_CONSOLA=ISNULL((SELECT ID FROM [FNNGS-TEST-01].FEWS.DBO.FEWS_ENCABEZADO AS CONSOLA, AST_FEWS_LOG
					WHERE	AST_FEWS_LOG.AS_ID=@@as_id AND
					CONSOLA.CUIT= AST_FEWS_LOG.CUIT_EMPRESA COLLATE DATABASE_DEFAULT AND
					CONSOLA.CONCEPTO=AST_FEWS_LOG.CONCEPTO_FACTURA  COLLATE DATABASE_DEFAULT AND
					CONSOLA.FECHA_CBTE=AST_FEWS_LOG.FECHA_COMPROBANTE COLLATE DATABASE_DEFAULT AND
					CONSOLA.TIPO_CBTE=AST_FEWS_LOG.TIPO_COMPROBANTE  COLLATE DATABASE_DEFAULT AND
					CONSOLA.PUNTO_VTA=AST_FEWS_LOG.PUNTO_VENTA COLLATE DATABASE_DEFAULT AND	
					CONSOLA.CBTE_NRO=AST_FEWS_LOG.NUMERO_COMPROBANTE COLLATE DATABASE_DEFAULT AND
					CONSOLA.TIPO_DOC=AST_FEWS_LOG.TIPODOC_CLIENTE COLLATE DATABASE_DEFAULT AND
					CONSOLA.NRO_DOC=AST_FEWS_LOG.NRODOC_CLIENTE COLLATE DATABASE_DEFAULT AND
					CONSOLA.IMP_TOTAL=AST_FEWS_LOG.IMPORTE_TOTAL	COLLATE DATABASE_DEFAULT),-1)
  RETURN @ID_CONSOLA
END
GO
